class Solution {
public:
    int binarySearch(int arr[], int n, int target) {
        int low = 0;
        int high = n - 1;
        while (low <= high) {
            int mid = (low + high) / 2;
            if (arr[mid] == target) {
                return mid;
            } else if (arr[mid] > target) {
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        if (low == high && arr[low] == target) {
            return low;
        }
        return -1;
    }
};

